mapper.select:
SELECT cm.*, s.nickname AS sender_nickname, s.avatar AS sender_avatar, r.nickname AS receiver_nickname, r.avatar AS receiver_avatar, p.title AS product_title, p.price AS product_price, (SELECT pi.image_url FROM product_image pi WHERE pi.product_id = cm.product_id AND pi.is_cover = 1 LIMIT 1) AS product_cover_image FROM chat_message cm LEFT JOIN `user` s ON cm.sender_id = s.id LEFT JOIN `user` r ON cm.receiver_id = r.id LEFT JOIN product p ON cm.product_id = p.id WHERE ((cm.sender_id = #{userId1} AND cm.receiver_id = #{userId2}) OR (cm.sender_id = #{userId2} AND cm.receiver_id = #{userId1}))
AND cm.product_id = #{productId}
ORDER BY cm.create_time ASC
